<template>
	<view class="edit-page">
		<view class="form-box">
			<!-- еӨҙеғҸ -->
			<view class="avatar-section">
				<image class="avatar" src="/static/userImg/baby.png" mode="aspectFill"></image>
				<view class="avatar-tip">еӣәе®ҡеӨҙеғҸ</view>
			</view>
			
			<!-- жҳөз§° -->
			<view class="form-item">
				<view class="form-label">жҳөз§°</view>
				<input 
					class="form-input" 
					v-model="formData.nickName" 
					placeholder="иҜ·иҫ“е…Ҙжҳөз§°"
					maxlength="20"
				/>
			</view>
			
			<!-- е…Ҙеқ‘ж—¶й—ҙ -->
			<view class="form-item">
				<view class="form-label">е…Ҙеқ‘ж—¶й—ҙ</view>
				<uni-datetime-picker 
					type="date" 
					v-model="formData.startTime"
					placeholder="иҜ·йҖүжӢ©е…Ҙеқ‘ж—¶й—ҙ"
				/>
			</view>
			
			<!-- е–ңж¬ўзұ»еһӢ -->
			<view class="form-item">
				<view class="form-label">жҲ‘зҡ„еұһжҖ§/жҲ‘з«ҷ</view>
				<input 
					class="form-input" 
					v-model="formData.loveType" 
					placeholder="й»ҳи®Өе®Үйқ’99"
					maxlength="20"
				/>
			</view>
			
			<!-- еҫ®дҝЎеҸ· -->
			<view class="form-item">
				<view class="form-label">еҫ®дҝЎеҸ·</view>
				<input 
					class="form-input" 
					v-model="formData.wxid" 
					placeholder="иҜ·иҫ“е…Ҙеҫ®дҝЎеҸ·"
					maxlength="30"
				/>
			</view>
		</view>
		
		<!-- дҝқеӯҳжҢүй’® -->
		<view class="btn-box">
			<button class="btn-save" @click="saveProfile">дҝқеӯҳ</button>
		</view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				formData: {
					nickName: '',
					startTime: '',
					loveType: 'е®Үйқ’99',
					wxid: ''
				},
				userInfo: {}
			}
		},
		onLoad(options) {
			// иҺ·еҸ–дј йҖ’зҡ„еҸӮж•°
			if (options.nickName) {
				this.formData.nickName = decodeURIComponent(options.nickName)
			}
			if (options.startTime) {
				this.formData.startTime = decodeURIComponent(options.startTime)
			}
			if (options.loveType) {
				this.formData.loveType = decodeURIComponent(options.loveType) || 'е®Үйқ’99'
			}
			if (options.wxid) {
				this.formData.wxid = decodeURIComponent(options.wxid)
			}
			
			// иҺ·еҸ–з”ЁжҲ·дҝЎжҒҜ
			try {
				const userInfo = uni.getStorageSync('userInfo')
				this.userInfo = JSON.parse(userInfo)
			} catch (e) {
				console.error('иҺ·еҸ–з”ЁжҲ·дҝЎжҒҜеӨұиҙҘ', e)
			}
		},
		methods: {
			saveProfile() {
				// йӘҢиҜҒеҝ…еЎ«йЎ№
				if (!this.formData.nickName) {
					uni.showModal({
						content: 'иҜ·иҫ“е…Ҙжҳөз§°',
						showCancel: false
					})
					return
				}
				
				if (!this.userInfo._id) {
					uni.showModal({
						content: 'иҜ·е…Ҳзҷ»еҪ•',
						showCancel: false
					})
					return
				}
				
				uni.showLoading({ title: 'дҝқеӯҳдёӯ...' })
				
				uniCloud.callFunction({
					name: 'user',
					data: {
						action: 'update',
						_id: this.userInfo._id,
						open_id: this.userInfo.mp_wx_openid,
						user_info: {
							nickName: this.formData.nickName,
							avatarUrl: '/static/userImg/baby.png'
						},
						startTime: this.formData.startTime,
						loveType: this.formData.loveType || 'е®Үйқ’99',
						wxid: this.formData.wxid
					}
				}).then((res) => {
					uni.hideLoading()
					if (res.result) {
						// жӣҙж–°жң¬ең°еӯҳеӮЁ
						const userInfo = uni.getStorageSync('userInfo')
						if (userInfo) {
							const userObj = JSON.parse(userInfo)
							userObj.nickName = this.formData.nickName
							userObj.startTime = this.formData.startTime
							userObj.loveType = this.formData.loveType || 'е®Үйқ’99'
							userObj.wxid = this.formData.wxid
							uni.setStorageSync('userInfo', JSON.stringify(userObj))
						}
						
						uni.showModal({
							content: 'дҝқеӯҳжҲҗеҠҹ',
							showCancel: false,
							success: () => {
								// иҝ”еӣһдёҠдёҖйЎөе№¶еҲ·ж–°
								uni.navigateBack()
							}
						})
					}
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `дҝқеӯҳеӨұиҙҘпјҡ${err.message}`,
						showCancel: false
					})
				})
			}
		}
	}
</script>

<style lang="scss">
.edit-page {
	min-height: 100vh;
	background: linear-gradient(180deg, #cff8f5 0%, #e6cffc 100%);
	padding: 20rpx 30rpx 120rpx;
}

.form-box {
	background: #fff;
	border-radius: 24rpx;
	padding: 40rpx;
	margin-top: 20rpx;
	box-shadow: 0 4rpx 16rpx rgba(0, 0, 0, 0.08);
}

.avatar-section {
	display: flex;
	flex-direction: column;
	align-items: center;
	margin-bottom: 40rpx;
	
	.avatar {
		width: 160rpx;
		height: 160rpx;
		border-radius: 50%;
		border: 4rpx solid #2df3e3;
		margin-bottom: 16rpx;
	}
	
	.avatar-tip {
		font-size: 24rpx;
		color: #999;
	}
}

.form-item {
	margin-bottom: 32rpx;
	
	&:last-child {
		margin-bottom: 0;
	}
	
	.form-label {
		font-size: 28rpx;
		color: #333;
		font-weight: bold;
		margin-bottom: 16rpx;
	}
	
	.form-input {
		height: 80rpx;
		background: #f5f5f5;
		border-radius: 12rpx;
		padding: 0 20rpx;
		font-size: 28rpx;
	}
}

.btn-box {
	position: fixed;
	bottom: 0;
	left: 0;
	right: 0;
	padding: 20rpx 30rpx;
	background: #fff;
	box-shadow: 0 -4rpx 12rpx rgba(0,0,0,0.1);
	
	.btn-save {
		width: 100%;
		height: 88rpx;
		background: linear-gradient(135deg, #31eee0 0%, #a9a9d9 100%);
		color: #fff;
		border-radius: 44rpx;
		font-size: 32rpx;
		border: none;
	}
}
</style>
